// ── SEARCH FUNCTION ──────────────────────────────────────────
export function searchFoods(query, filters = {}) {
  let results = INDIAN_FOOD_DB.filter(f => f.serving > 0);

  if (query && query.trim().length > 0) {
    const q = query.toLowerCase().trim();
    results = results.filter(f =>
      f.name.toLowerCase().includes(q) ||
      f.subCategory.toLowerCase().includes(q) ||
      (f.brand && f.brand.toLowerCase().includes(q)) ||
      f.tags.some(t => t.includes(q))
    );
  }

  if (filters.category) results = results.filter(f => f.category === filters.category);
  if (filters.tag) results = results.filter(f => f.tags.includes(filters.tag));
  if (filters.maxCal) results = results.filter(f => f.cal <= filters.maxCal);
  if (filters.minProtein) results = results.filter(f => f.p >= filters.minProtein);

  return results.slice(0, filters.limit || 30);
}

